function loadHeader(){fetch("assets/components/header.html").then(e=>e.text()).then(e=>{const t=document.getElementById("header-placeholder");if(!t)return;t.innerHTML=e,highlightActiveLink();const n=document.getElementById("hamburger-btn"),r=document.getElementById("nav-menu");n&&r&&n.addEventListener("click",()=>{r.classList.toggle("show")})}).catch(e=>{console.error("Error loading header:",e)})}function highlightActiveLink(){const e=window.location.pathname.split("/").pop();document.querySelectorAll(".nav-link").forEach(t=>{t.getAttribute("href")===e&&t.classList.add("nav-active")})}document.addEventListener("DOMContentLoaded",()=>{loadHeader()}),"serviceWorker"in navigator&&window.addEventListener("load",()=>{navigator.serviceWorker.register("/service-worker.js").catch(e=>console.error("SW registration failed:",e))});
